const stdout = $('SSH Execute').first().json.stdout || '';
const now = new Date();
const todayStr = now.toISOString().split('T')[0];
const timeStr = now.toTimeString().split(' ')[0];

// Dividir salida por secciones
const sections = {};
const sectionNames = ['MEMORY', 'DISK', 'CONTAINERS', 'STATS', 'BACKUPS'];
let currentSection = 'MEMORY';
sections[currentSection] = [];

const lines = stdout.split('\n');
for (const line of lines) {
  let matched = false;
  for (const name of sectionNames) {
    if (line.includes(`=== ${name} ===`)) {
      currentSection = name;
      sections[currentSection] = [];
      matched = true;
      break;
    }
  }
  if (!matched) {
    sections[currentSection].push(line);
  }
}

// 1. Parsear Memoria
let totalMem = 0;
let usedMem = 0;
let memPercent = 0;
const memLine = sections['MEMORY'].find(l => l.trim().startsWith('Mem:'));
if (memLine) {
  const parts = memLine.trim().split(/\s+/);
  totalMem = parseInt(parts[1], 10);
  usedMem = parseInt(parts[2], 10);
  memPercent = (usedMem / totalMem) * 100;
}

// 2. Parsear Disco
let diskPercent = 0;
const diskLine = sections['DISK'].find(l => l.includes(' /'));
if (diskLine) {
  const parts = diskLine.trim().split(/\s+/);
  const usePart = parts.find(p => p.endsWith('%'));
  if (usePart) {
    diskPercent = parseInt(usePart.replace('%', ''), 10);
  }
}

// 3. Parsear Contenedores
const criticalContainers = [
  { key: 'centrodetutoriasweb', name: 'Centro de Tutorías Web', pattern: /centrodetutoriasweb/i },
  { key: 'paperclipapp', name: 'Paperclip App', pattern: /paperclipapp/i },
  { key: 'paperclipdb', name: 'Paperclip DB', pattern: /paperclipdb/i },
  { key: 'n8n', name: 'n8n App', pattern: /n8n-1/i },
  { key: 'n8n-postgres', name: 'n8n Postgres DB', pattern: /postgres-1/i },
  { key: 'supabase-db', name: 'Supabase DB', pattern: /supabase-db/i }
];

const containerStatus = {};
const missingContainers = [];
const stoppedContainers = [];

for (const c of criticalContainers) {
  const matchedLine = sections['CONTAINERS'].find(l => c.pattern.test(l));
  if (!matchedLine) {
    containerStatus[c.key] = 'Missing';
    missingContainers.push(c.name);
  } else {
    if (matchedLine.includes('Up')) {
      containerStatus[c.key] = 'Running';
    } else {
      containerStatus[c.key] = 'Stopped/Restarting';
      stoppedContainers.push(`${c.name} (${matchedLine.trim()})`);
    }
  }
}

// 4. Parsear Backups
const requiredBackups = [
  { key: 'n8n', name: 'n8n_backup.sql.gz' },
  { key: 'paperclip', name: 'paperclip_backup.sql.gz' },
  { key: 'supabase', name: 'supabase_backup.sql.gz' }
];

const backupStatus = {};
const missingBackups = [];
const emptyBackups = [];

for (const b of requiredBackups) {
  const matchedLine = sections['BACKUPS'].find(l => l.includes(b.name));
  if (!matchedLine) {
    backupStatus[b.key] = 'Missing';
    missingBackups.push(b.name);
  } else {
    const parts = matchedLine.trim().split(/\s+/);
    const sizeStr = parts[4];
    if (sizeStr === '0' || sizeStr === '0B') {
      backupStatus[b.key] = 'Empty (0 bytes)';
      emptyBackups.push(b.name);
    } else {
      backupStatus[b.key] = `OK (${sizeStr})`;
    }
  }
}

// 5. Evaluar Alertas
let alert = false;
const alertReasons = [];
let priority = 'low';

if (memPercent > 85) {
  alert = true;
  priority = 'high';
  alertReasons.push(`Uso de RAM crítico: ${memPercent.toFixed(1)}% (Límite: 85%)`);
} else if (memPercent > 75) {
  alert = true;
  priority = 'medium';
  alertReasons.push(`Uso de RAM elevado: ${memPercent.toFixed(1)}% (Límite preventivo: 75%)`);
}

if (diskPercent > 85) {
  alert = true;
  priority = 'high';
  alertReasons.push(`Uso de Disco crítico: ${diskPercent}% (Límite: 85%)`);
} else if (diskPercent > 75) {
  alert = true;
  if (priority !== 'high') priority = 'medium';
  alertReasons.push(`Uso de Disco elevado: ${diskPercent}% (Límite preventivo: 75%)`);
}

if (missingContainers.length > 0) {
  alert = true;
  priority = 'high';
  alertReasons.push(`Contenedores críticos faltantes: ${missingContainers.join(', ')}`);
}

if (stoppedContainers.length > 0) {
  alert = true;
  priority = 'high';
  alertReasons.push(`Contenedores críticos no activos: ${stoppedContainers.join(', ')}`);
}

if (missingBackups.length > 0) {
  alert = true;
  priority = 'high';
  alertReasons.push(`Copias de seguridad faltantes: ${missingBackups.join(', ')}`);
}

if (emptyBackups.length > 0) {
  alert = true;
  priority = 'high';
  alertReasons.push(`Copias de seguridad vacías (0 bytes): ${emptyBackups.join(', ')}`);
}

// Generar reporte en Markdown
let markdownReport = `### 🖥️ REPORTE DE SALUD DEL SERVIDOR - CEDETU (${todayStr} ${timeStr})\n\n`;
if (alert) {
  markdownReport += `⚠️ **ALERTA DE SISTEMA RELEVADA** (Prioridad: **${priority.toUpperCase()}**)\n`;
  alertReasons.forEach(reason => {
    markdownReport += `- 🔴 ${reason}\n`;
  });
  markdownReport += `\n---\n\n`;
} else {
  markdownReport += `✅ **Sistema saludable.** No se detectaron anomalías ni alertas.\n\n---\n\n`;
}

markdownReport += `#### 1. Recursos del Sistema\n`;
markdownReport += `*   **Uso de Memoria RAM:** ${memPercent.toFixed(1)}% (${usedMem}MB usados de ${totalMem}MB)\n`;
markdownReport += `*   **Uso de Disco Duro:** ${diskPercent}% ocupado\n\n`;

markdownReport += `#### 2. Estado de Contenedores Críticos\n`;
criticalContainers.forEach(c => {
  const status = containerStatus[c.key] === 'Running' ? '🟢 Activo' : `🔴 ${containerStatus[c.key]}`;
  markdownReport += `*   **${c.name}:** ${status}\n`;
});
markdownReport += `\n`;

markdownReport += `#### 3. Estado de Copias de Seguridad\n`;
requiredBackups.forEach(b => {
  const status = backupStatus[b.key].startsWith('OK') ? `🟢 ${backupStatus[b.key]}` : `🔴 ${backupStatus[b.key]}`;
  markdownReport += `*   **${b.name}:** ${status}\n`;
});

markdownReport += `\n\n*Informe automatizado generado por DevOps Agent. En caso de fallas de prioridad alta/media, se genera un issue para su atención inmediata.*`;

return [{
    json: {
      memory: {
        total: totalMem,
        used: usedMem,
        percent: memPercent
      },
      disk: {
        percent: diskPercent
      },
      containers: containerStatus,
      backups: backupStatus,
      alert,
      priority,
      alertReasons,
      markdownReport
    }
  }];
